CREATE TABLE american_users (
  id INT NOT NULL AUTO_INCREMENT PRIMARY KEY,
  name VARCHAR(255),
  surname VARCHAR(255),
  phone VARCHAR(255),
  email VARCHAR(255),
  birth_date VARCHAR(255),
  country VARCHAR(255),
  city VARCHAR(255),
  postal_code VARCHAR(255),
  address VARCHAR(255),
  signup_date VARCHAR(255),
  user_segment VARCHAR(255),
  income_band VARCHAR(255)
);
